-- =============================================================================
-- SHADOW FORGE — GENESIS SET CARD SEED (auto-generated from src/game/cards.ts)
-- 150 collectible cards. Idempotent via ON CONFLICT (code).
-- =============================================================================

on conflict (code) do update set
  name = excluded.name, clan = excluded.clan, card_type = excluded.card_type,
  rarity = excluded.rarity, cost = excluded.cost, attack = excluded.attack,
  health = excluded.health, rules_text = excluded.rules_text, image_url = excluded.image_url;
